mapper.select:
select count(*)
from appointment
where appointment_time >= #{beginTime}
  and appointment_time < #{endTime}

select count(*)
from order_info
where create_time >= #{beginTime}
  and create_time < #{endTime}

select ifnull(sum(amount), 0)
from order_info
where pay_status = 1
  and create_time >= #{beginTime}
  and create_time < #{endTime}
